{"content": "#!/usr/bin/env python3
"""Convert validation parquet to JSONL format."""
import pandas as pd
import json
import numpy as np

df = pd.read_parquet('context/validation-00000-of-00001.parquet')

records = []
for _, row in df.iterrows():
    choices = row['choices']
    # Handle the dict with numpy arrays
    if isinstance(choices, dict):
        labels = choices['label']
        texts = choices['text']
        if isinstance(labels, np.ndarray):
            labels = labels.tolist()
        if isinstance(texts, np.ndarray):
            texts = texts.tolist()
        choices_formatted = {"label": labels, "text": texts}
    else:
        choices_formatted = choices

    record = {
        "id": row["id"],
        "question": row["question"],
        "question_concept": row["question_concept"],
        "choices": choices_formatted,
        "answerKey": row["answerKey"]
    }
    records.append(record)

with open('validation.jsonl', 'w', encoding='utf-8') as f:
    for record in records:
        f.write(json.dumps(record, ensure_ascii=False) + '\n')

print(f"Converted {len(records)} records to validation.jsonl")
